final:
module graycode_counter (
    input wire clk,
    input wire rst,
    output reg [2:0] gray_out
);

    reg [2:0] obf_binary_count;

    always @(posedge clk or posedge rst) begin
        if (rst)
            obf_binary_count <= 3'b000;
        else
            obf_binary_count <= obf_binary_count + 1;
    end

    always @(*) begin
        gray_out = obf_binary_count ^ (obf_binary_count >> 1);
    end

endmodule
